def run_async(coro):
    """Helper to run an async function from a synchronous context."""
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    return loop.run_until_complete(coro)


# ─── Data Fetching Helpers ───────────────────────
def fetch_weather_by_city(city_name):
    """Bridge to weather_service."""
    try:
        geo = run_async(ws.geocode_city(city_name))
        if not geo:
            st.error(f"City '{city_name}' not found")
            return None
        return run_async(ws.fetch_full_weather_data(geo, os.getenv("GROQ_API_KEY", ""), st.session_state.get("user_profile")))
    except Exception as e:
        st.error(f"⚠️ Weather Service Error: Could not connect to API ({type(e).__name__}). Please check your internet connection.")
        return None

def fetch_weather_by_coords(lat, lon):
    """Bridge to weather_service."""
    try:
        geo = run_async(ws.reverse_geocode(lat, lon))
        if not geo:
            geo = {"name": f"{lat:.2f}°, {lon:.2f}°", "country": "", "admin1": "",
                   "latitude": lat, "longitude": lon, "timezone": "auto", "population": None}
        return run_async(ws.fetch_full_weather_data(geo, os.getenv("GROQ_API_KEY", ""), st.session_state.get("user_profile")))
    except Exception as e:
        st.error(f"⚠️ Weather Service Error: Could not connect to API ({type(e).__name__}). Please check your internet connection.")
        return None




def reminder_background_worker():
    """Background polling thread for triggering email reminders."""
    while True:
        try:
            res = db.get_pending_reminders()
            if res.get("success") and res.get("reminders"):
                for rem in res["reminders"]:
                    # Fetch contextual weather for the reminder's location
                    geo = {
                        "latitude": rem["lat"],
                        "longitude": rem["lon"],
                        "name": rem["location_name"],
                        "timezone": "auto"
                    }
                    try:
                        # Assuming _fetch_full_weather is an async function in weather_service
                        w_data = run_async(ws.get_current_weather(rem["lat"], rem["lon"]))
                        
                        prompt = f"""
                        You are WeatherTwin, an AI Climate Intelligence Assistant.
                        The user has scheduled an event: '{rem['description']}' at {rem['event_datetime']} in {rem['location_name']}.
                        The current weather at this location: 
                        - Temperature: {w_data['temperature']}°C
                        - Condition: {w_data['condition']}
                        - Precipitation: {w_data['precipitation']}mm
                        - Wind: {w_data['wind_speed']}km/h
                        
                        Please write a friendly, helpful 2-paragraph email advisory for the user. 
                        Provide insights on the weather, and make suggestions on if they should start early or take precautions.
                        Keep it concise but highly valuable. Do not use markdown headers, just plain text paragraphs.
                        """
                        insight = llm.generate_dynamic_insight(prompt)
                    except Exception as e:
                        insight = f"We couldn't generate a dynamic weather insight for this event, but here is your reminder for {rem['description']} at {rem['location_name']}!"
                    
                    # Send email
                    em.send_scheduled_notification_email(
                        rem["email"],
                        rem["description"],
                        str(rem["event_datetime"]),
                        rem["location_name"],
                        insight
                    )
                    
                    # Mark sent
                    db.mark_reminder_sent(rem["id"])
        except Exception as e:
            print(f"Reminder background thread error: {e}")
        
        # Poll every 60 seconds
        time.sleep(60)

# Start background thread if not already running
if "reminder_thread_started" not in st.session_state:
    t = threading.Thread(target=reminder_background_worker, daemon=True)
    t.start()
    st.session_state.reminder_thread_started = True

