st.session_state.checked_cookie = False



# Auto-login via cookie
if not st.session_state.logged_in and not st.session_state.checked_cookie:
    token = cookie_manager.get(cookie="weathertwin_remember")
    if token:
        res = db.verify_remember_token(token)
        if res["success"]:
            st.session_state.logged_in = True
            st.session_state.user_info = res["user"]
            st.session_state.checked_cookie = True
            st.rerun()


