WEATHER_EMOJI = {
    'sunny': '☀️', 'partly-cloudy': '⛅', 'cloudy': '☁️',
    'fog': '🌫️', 'drizzle': '🌦️', 'rain': '🌧️',
    'snow': '❄️', 'storm': '⛈️',
}

def get_emoji(icon, is_day=True):
    if icon == 'sunny' and not is_day:
        return '🌙'
    return WEATHER_EMOJI.get(icon, '☁️')

def day_name(date_str):
    from datetime import datetime
    d = datetime.strptime(date_str, "%Y-%m-%d")
    today = datetime.now()
    if d.date() == today.date():
        return "Today"
    from datetime import timedelta
    if d.date() == (today + timedelta(days=1)).date():
        return "Tmrw"
    return d.strftime("%a")








def _generate_local_insight(current, forecast):
    """Generate a practical clothing/activity insight without the LLM."""
    temp = current.get("temperature", 20)
    feels = current.get("feels_like", temp)
    wind = current.get("wind_speed", 0)
    humidity = current.get("humidity", 50)
    precip = current.get("precipitation", 0)
    condition = current.get("condition", "").lower()
    is_day = current.get("is_day", True)

    parts = []

    # Clothing suggestion based on feels-like temperature
    if feels <= 0:
        parts.append(f"At {temp}°C (feels like {feels}°C), bundle up with a heavy winter coat, gloves, scarf, and warm layers.")
    elif feels <= 10:
        if is_day:
            parts.append(f"With {temp}°C (feels like {feels}°C), a warm jacket and layering up is recommended.")
        else:
            parts.append(f"A chilly {temp}°C evening (feels like {feels}°C) — grab a warm coat before heading out.")
    elif feels <= 18:
        if is_day:
            parts.append(f"At {temp}°C (feels like {feels}°C), a light jacket or sweater should keep you comfortable.")
        else:
            parts.append(f"A mild {temp}°C evening (feels like {feels}°C) — a light jacket is a good idea for the night chill.")
    elif feels <= 25:
        if is_day:
            parts.append(f"A pleasant {temp}°C (feels like {feels}°C) — light, breathable clothing is ideal. Don't forget sunscreen!")
        else:
            parts.append(f"A warm {temp}°C evening (feels like {feels}°C) — light layers are perfect for tonight.")
    else:
        if is_day:
            parts.append(f"It's a hot {temp}°C (feels like {feels}°C) — wear light, loose clothing, stay hydrated, and use sunscreen.")
        else:
            parts.append(f"A warm {temp}°C night (feels like {feels}°C) — keep it light and stay hydrated.")

    # Rain/weather specifics
    if precip > 0 or "rain" in condition or "drizzle" in condition:
        parts.append("Don't forget an umbrella or raincoat!")
    elif "snow" in condition:
        parts.append("Snow expected — wear waterproof boots and warm layers.")
    elif "fog" in condition:
        if is_day:
            parts.append("Foggy conditions — drive carefully and allow extra travel time.")
        else:
            parts.append("Foggy night — visibility is low, drive carefully and wear reflective/bright clothing if walking.")

    # Wind advisory
    if wind > 40:
        parts.append(f"Strong winds at {wind} km/h — avoid cycling and secure loose items.")
    elif wind > 25:
        parts.append(f"Breezy at {wind} km/h — a windbreaker would be helpful.")

    # Activity suggestion (day vs night)
    if is_day:
        if precip == 0 and feels >= 15 and feels <= 28 and wind < 30:
            parts.append("Great day for outdoor activities like walking, jogging, or having a picnic!")
        elif precip == 0 and feels >= 5 and wind < 25:
            parts.append("A decent day for a brisk walk or visiting local attractions.")
        elif precip > 0:
            parts.append("Consider indoor activities like visiting a museum, café, or shopping.")
    else:
        if precip == 0 and feels >= 12 and wind < 25:
            parts.append("A lovely evening for a stroll, outdoor dining, or stargazing!")
        elif precip == 0 and feels >= 5 and wind < 25:
            parts.append("Good evening for a quick walk or catching a show.")
        elif precip > 0:
            parts.append("A cozy night to stay in — grab a warm drink and enjoy a movie or book.")

    return " ".join(parts)


# ─── Severe weather detection helper ─────────────
def _detect_severe(cur):
    """Detect severe weather conditions from current weather data."""
    alerts = []
    condition = cur.get("condition", "").lower()
    temp = cur.get("temperature", 20)
    wind = cur.get("wind_speed", 0)
    if "thunderstorm" in condition or "storm" in condition:
        alerts.append(("⛈️ Thunderstorm", "#f43f5e"))
    if "heavy snow" in condition:
        alerts.append(("❄️ Heavy Snow", "#60a5fa"))
    elif "snow" in condition:
        alerts.append(("🌨️ Snow", "#93c5fd"))
    if "heavy rain" in condition or "violent" in condition:
        alerts.append(("🌊 Heavy Rain / Flood Risk", "#f97316"))
    elif "rain" in condition and "slight" not in condition:
        alerts.append(("🌧️ Rain", "#fbbf24"))
    if wind > 60:
        alerts.append(("🌪️ Extreme Wind", "#f43f5e"))
    elif wind > 40:
        alerts.append(("💨 High Wind", "#f97316"))
    if temp > 40:
        alerts.append(("🔥 Extreme Heat", "#f43f5e"))
    elif temp < -15:
        alerts.append(("🥶 Extreme Cold", "#60a5fa"))
    if "fog" in condition:
        alerts.append(("🌫️ Low Visibility", "#fbbf24"))
    return alerts




